record_types.code:
type Format_Type is
   record
      Fill_Defined      : Boolean := False;
      Fill              : Wide_Character := ' ';
      Align             : Align_Type := None;
      Sign              : Sign_Type := None;
      Include_Base      : Boolean := False;
      Width             : Natural := 0;
      Precision_Defined : Boolean := False;
      Precision         : Natural := 0;
      Data              : Data_Type := None;
   end record;

subprograms.code:
function Align (Value     : Wide_String;
                Fill      : Wide_Character;
                Width     : Natural;
                Alignment : Align_Type;
                Prefix    : Wide_String := "") return Wide_String
